module ComputeQuotaResourceConfig =
  struct
    type nonrec t =
      {
      instanceType: ClusterInstanceType.t
        [@ocaml.doc
          "The instance type of the instance group for the cluster."];
      count: InstanceCount.t option
        [@ocaml.doc
          "The number of instances to add to the instance group of a SageMaker HyperPod cluster."];
      accelerators: AcceleratorsAmount.t option
        [@ocaml.doc
          "The number of accelerators to allocate. If you don't specify a value for vCPU and MemoryInGiB, SageMaker AI automatically allocates ratio-based values for those parameters based on the number of accelerators you provide. For example, if you allocate 16 out of 32 total accelerators, SageMaker AI uses the ratio of 0.5 and allocates values to vCPU and MemoryInGiB."];
      vCpu: VCpuAmount.t option
        [@ocaml.doc
          "The number of vCPU to allocate. If you specify a value only for vCPU, SageMaker AI automatically allocates ratio-based values for MemoryInGiB based on this vCPU parameter. For example, if you allocate 20 out of 40 total vCPU, SageMaker AI uses the ratio of 0.5 and allocates values to MemoryInGiB. Accelerators are set to 0."];
      memoryInGiB: MemoryInGiBAmount.t option
        [@ocaml.doc
          "The amount of memory in GiB to allocate. If you specify a value only for this parameter, SageMaker AI automatically allocates a ratio-based value for vCPU based on this memory that you provide. For example, if you allocate 200 out of 400 total memory in GiB, SageMaker AI uses the ratio of 0.5 and allocates values to vCPU. Accelerators are set to 0."];
      acceleratorPartition: AcceleratorPartitionConfig.t option
        [@ocaml.doc
          "The accelerator partition configuration for fractional GPU allocation."]}
    let context_ = "ComputeQuotaResourceConfig"
    let make ?count =
      fun ?accelerators ->
        fun ?vCpu ->
          fun ?memoryInGiB ->
            fun ?acceleratorPartition ->
              fun ~instanceType ->
                fun () ->
                  {
                    count;
                    accelerators;
                    vCpu;
                    memoryInGiB;
                    acceleratorPartition;
                    instanceType
                  }
    let to_value x =
      structure_to_value
        [("InstanceType",
           (Some (ClusterInstanceType.to_value x.instanceType)));
        ("Count", (Option.map x.count ~f:InstanceCount.to_value));
        ("Accelerators",
          (Option.map x.accelerators ~f:AcceleratorsAmount.to_value));
        ("VCpu", (Option.map x.vCpu ~f:VCpuAmount.to_value));
        ("MemoryInGiB",
          (Option.map x.memoryInGiB ~f:MemoryInGiBAmount.to_value));
        ("AcceleratorPartition",
          (Option.map x.acceleratorPartition
             ~f:AcceleratorPartitionConfig.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let acceleratorPartition =
        (Option.map ~f:AcceleratorPartitionConfig.of_xml)
          (Xml.child xml_arg0 "AcceleratorPartition") in
      let memoryInGiB =
        (Option.map ~f:MemoryInGiBAmount.of_xml)
          (Xml.child xml_arg0 "MemoryInGiB") in
      let vCpu =
        (Option.map ~f:VCpuAmount.of_xml) (Xml.child xml_arg0 "VCpu") in
      let accelerators =
        (Option.map ~f:AcceleratorsAmount.of_xml)
          (Xml.child xml_arg0 "Accelerators") in
      let count =
        (Option.map ~f:InstanceCount.of_xml) (Xml.child xml_arg0 "Count") in
      let instanceType =
        ClusterInstanceType.of_xml
          (Xml.child_exn ~context:context_ xml_arg0 "InstanceType") in
      make ?acceleratorPartition ?memoryInGiB ?vCpu ?accelerators ?count
        ~instanceType ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let acceleratorPartition =
        field_map json__ "AcceleratorPartition"
          AcceleratorPartitionConfig.of_json in
      let memoryInGiB =
        field_map json__ "MemoryInGiB" MemoryInGiBAmount.of_json in
      let vCpu = field_map json__ "VCpu" VCpuAmount.of_json in
      let accelerators =
        field_map json__ "Accelerators" AcceleratorsAmount.of_json in
      let count = field_map json__ "Count" InstanceCount.of_json in
      let instanceType =
        field_map_exn json__ "InstanceType" ClusterInstanceType.of_json in
      make ?acceleratorPartition ?memoryInGiB ?vCpu ?accelerators ?count
        ~instanceType ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "Configuration of the resources used for the compute allocation definition."]
