      let sourceArn =
        (Option.map ~f:AssociationEntityArn.of_xml)
          (Xml.child xml_arg0 "SourceArn") in
      make ?destinationArn ?sourceArn ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let destinationArn =
        field_map json__ "DestinationArn" AssociationEntityArn.of_json in
      let sourceArn =
        field_map json__ "SourceArn" AssociationEntityArn.of_json in
      make ?destinationArn ?sourceArn ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
