      structure_to_value
        [("S3OutputLocation", (Some (S3Uri.to_value x.s3OutputLocation)));
        ("TargetDevice",
          (Option.map x.targetDevice ~f:TargetDevice.to_value));
        ("TargetPlatform",
          (Option.map x.targetPlatform ~f:TargetPlatform.to_value));
        ("CompilerOptions",
          (Option.map x.compilerOptions ~f:CompilerOptions.to_value));
        ("KmsKeyId", (Option.map x.kmsKeyId ~f:KmsKeyId.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
