          (Xml.child xml_arg0 "CompilerOptions") in
      let targetPlatform =
        (Option.map ~f:TargetPlatform.of_xml)
          (Xml.child xml_arg0 "TargetPlatform") in
      let targetDevice =
        (Option.map ~f:TargetDevice.of_xml)
          (Xml.child xml_arg0 "TargetDevice") in
      let s3OutputLocation =
        S3Uri.of_xml
          (Xml.child_exn ~context:context_ xml_arg0 "S3OutputLocation") in
      make ?kmsKeyId ?compilerOptions ?targetPlatform ?targetDevice
        ~s3OutputLocation ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let kmsKeyId = field_map json__ "KmsKeyId" KmsKeyId.of_json in
      let compilerOptions =
        field_map json__ "CompilerOptions" CompilerOptions.of_json in
      let targetPlatform =
        field_map json__ "TargetPlatform" TargetPlatform.of_json in
      let targetDevice = field_map json__ "TargetDevice" TargetDevice.of_json in
      let s3OutputLocation =
        field_map_exn json__ "S3OutputLocation" S3Uri.of_json in
      make ?kmsKeyId ?compilerOptions ?targetPlatform ?targetDevice
