      allocationStrategy: HyperParameterTuningAllocationStrategy.t option
        [@ocaml.doc
          "The strategy that determines the order of preference for resources specified in InstanceConfigs used in hyperparameter optimization."];
      instanceConfigs: HyperParameterTuningInstanceConfigs.t option
        [@ocaml.doc
          "A list containing the configuration(s) for one or more resources for processing hyperparameter jobs. These resources include compute instances and storage volumes to use in model training jobs launched by hyperparameter tuning jobs. The AllocationStrategy controls the order in which multiple configurations provided in InstanceConfigs are used. If you only want to use a single instance configuration inside the HyperParameterTuningResourceConfig API, do not provide a value for InstanceConfigs. Instead, use InstanceType, VolumeSizeInGB and InstanceCount. If you use InstanceConfigs, do not provide values for InstanceType, VolumeSizeInGB or InstanceCount."]}
    let make ?instanceType =
      fun ?instanceCount ->
        fun ?volumeSizeInGB ->
          fun ?volumeKmsKeyId ->
            fun ?allocationStrategy ->
              fun ?instanceConfigs ->
                fun () ->
                  {
                    instanceType;
                    instanceCount;
                    volumeSizeInGB;
                    volumeKmsKeyId;
                    allocationStrategy;
                    instanceConfigs
                  }
    let to_value x =
      structure_to_value
        [("InstanceType",
           (Option.map x.instanceType ~f:TrainingInstanceType.to_value));
        ("InstanceCount",
          (Option.map x.instanceCount ~f:TrainingInstanceCount.to_value));
        ("VolumeSizeInGB",
          (Option.map x.volumeSizeInGB ~f:OptionalVolumeSizeInGB.to_value));
        ("VolumeKmsKeyId",
          (Option.map x.volumeKmsKeyId ~f:KmsKeyId.to_value));
        ("AllocationStrategy",
          (Option.map x.allocationStrategy
             ~f:HyperParameterTuningAllocationStrategy.to_value));
        ("InstanceConfigs",
          (Option.map x.instanceConfigs
             ~f:HyperParameterTuningInstanceConfigs.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let instanceConfigs =
        (Option.map ~f:HyperParameterTuningInstanceConfigs.of_xml)
          (Xml.child xml_arg0 "InstanceConfigs") in
      let allocationStrategy =
        (Option.map ~f:HyperParameterTuningAllocationStrategy.of_xml)
          (Xml.child xml_arg0 "AllocationStrategy") in
      let volumeKmsKeyId =
        (Option.map ~f:KmsKeyId.of_xml) (Xml.child xml_arg0 "VolumeKmsKeyId") in
      let volumeSizeInGB =
        (Option.map ~f:OptionalVolumeSizeInGB.of_xml)
          (Xml.child xml_arg0 "VolumeSizeInGB") in
      let instanceCount =
        (Option.map ~f:TrainingInstanceCount.of_xml)
          (Xml.child xml_arg0 "InstanceCount") in
      let instanceType =
        (Option.map ~f:TrainingInstanceType.of_xml)
          (Xml.child xml_arg0 "InstanceType") in
      make ?instanceConfigs ?allocationStrategy ?volumeKmsKeyId
        ?volumeSizeInGB ?instanceCount ?instanceType ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let instanceConfigs =
        field_map json__ "InstanceConfigs"
          HyperParameterTuningInstanceConfigs.of_json in
      let allocationStrategy =
        field_map json__ "AllocationStrategy"
          HyperParameterTuningAllocationStrategy.of_json in
      let volumeKmsKeyId = field_map json__ "VolumeKmsKeyId" KmsKeyId.of_json in
      let volumeSizeInGB =
        field_map json__ "VolumeSizeInGB" OptionalVolumeSizeInGB.of_json in
      let instanceCount =
        field_map json__ "InstanceCount" TrainingInstanceCount.of_json in
      let instanceType =
        field_map json__ "InstanceType" TrainingInstanceType.of_json in
      make ?instanceConfigs ?allocationStrategy ?volumeKmsKeyId
        ?volumeSizeInGB ?instanceCount ?instanceType ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "The configuration of resources, including compute instances and storage volumes for use in training jobs launched by hyperparameter tuning jobs. HyperParameterTuningResourceConfig is similar to ResourceConfig, but has the additional InstanceConfigs and AllocationStrategy fields to allow for flexible instance management. Specify one or more instance types, count, and the allocation strategy for instance selection. HyperParameterTuningResourceConfig supports the capabilities of ResourceConfig with the exception of KeepAlivePeriodInSeconds. Hyperparameter tuning jobs use warm pools by default, which reuse clusters between training jobs."]
